import{_ as e}from"./plugin-vue_export-helper-c27b6911.js";import{o as a,c as s,e as c}from"./app-be253e4c.js";const n={},o=c(`<h1 id="rm命令" tabindex="-1"><a class="header-anchor" href="#rm命令" aria-hidden="true">#</a> rm命令</h1><p><code>rm</code>命令用于删除一个文件或者目录。</p><h2 id="语法" tabindex="-1"><a class="header-anchor" href="#语法" aria-hidden="true">#</a> 语法</h2><div class="language-bash" data-ext="sh"><pre class="language-bash"><code><span class="token function">rm</span> <span class="token punctuation">[</span>OPTION<span class="token punctuation">]</span><span class="token punctuation">..</span>. <span class="token punctuation">[</span>FILE<span class="token punctuation">]</span><span class="token punctuation">..</span>.
</code></pre></div><h2 id="参数" tabindex="-1"><a class="header-anchor" href="#参数" aria-hidden="true">#</a> 参数</h2><ul><li><code>-f, --force</code>: 即使文件属性设为只读也直接删除，不逐一确认，此外忽略不存在的文件，不产生提示。</li><li><code>-i</code>: 删除之前逐一询问确认。</li><li><code>-I</code>: 在删除三个以上文件之前或在递归删除时提示一次，比<code>-i</code>提示的次数少，但仍然可以防止大多数错误。</li><li><code>--interactive[=WHEN]</code>: 根据<code>WHEN</code>提示，从不，一次<code>-I</code>或始终<code>-i</code>，如果没有<code>WHEN</code>，则始终提示。</li><li><code>--one-file-system</code>: 递归删除层次结构时，跳过文件系统上与相应命令行参数不同的任何目录。</li><li><code>--no-preserve-root</code>: 不特别对待<code>/</code>。</li><li><code>--preserve-root</code>: 不要删除<code>/</code>，默认选项。</li><li><code>-r, -R, --recursive</code>: 递归删除目录及其内容。</li><li><code>-d, --dir</code>: 删除空目录。</li><li><code>-v, --verbose</code>: 输出执行过程。</li><li><code>--help</code>: 输出帮助信息。</li><li><code>--version</code>: 输出版本信息。</li></ul><h2 id="示例" tabindex="-1"><a class="header-anchor" href="#示例" aria-hidden="true">#</a> 示例</h2><p>删除文件<code>file.txt</code>，如果文件是写保护的，则将提示是否确认要删除。</p><div class="language-bash" data-ext="sh"><pre class="language-bash"><code><span class="token function">rm</span> file.txt
</code></pre></div><p>删除文件<code>file.txt</code>，即使文件是写保护的也不会有确认提示。</p><div class="language-bash" data-ext="sh"><pre class="language-bash"><code><span class="token function">rm</span> <span class="token parameter variable">-f</span> file.txt
</code></pre></div><p>删除当前目录中的所有文件，如果文件是写保护的，则在<code>rm</code>删除之前将提示。</p><div class="language-bash" data-ext="sh"><pre class="language-bash"><code><span class="token function">rm</span> *
</code></pre></div><p>删除当前目录中的所有文件，<code>rm</code>将不会有任何提示。</p><div class="language-bash" data-ext="sh"><pre class="language-bash"><code><span class="token function">rm</span> <span class="token parameter variable">-f</span> *
</code></pre></div><p>尝试删除当前目录中的每个文件，但在删除每个文件之前提示确认。</p><div class="language-bash" data-ext="sh"><pre class="language-bash"><code><span class="token function">rm</span> <span class="token parameter variable">-i</span> *
</code></pre></div><p>删除当前目录中的每个文件，提示确认是否删除三个以上的文件。</p><div class="language-bash" data-ext="sh"><pre class="language-bash"><code><span class="token function">rm</span> <span class="token parameter variable">-I</span> *
</code></pre></div><p>删除目录<code>directory</code>及其包含的所有文件和目录，果<code>rm</code>尝试删除的文件或目录具有写保护，则将提示是否确实要删除。</p><div class="language-bash" data-ext="sh"><pre class="language-bash"><code><span class="token function">rm</span> <span class="token parameter variable">-r</span> directory
</code></pre></div><p>删除目录<code>directory</code>及其包含的所有文件和目录，不会有任何确认提示。</p><div class="language-bash" data-ext="sh"><pre class="language-bash"><code><span class="token function">rm</span> <span class="token parameter variable">-rf</span> mydirectory
</code></pre></div>`,23),d=[o];function r(t,l){return a(),s("div",null,d)}const h=e(n,[["render",r],["__file","rm.html.vue"]]);export{h as default};
